#!/usr/bin/env python3
import sys, base64, hashlib, os, stat
from pathlib import Path

ENCRYPTED_B64 = ""
KEY_B64 = "EWWeucajPSSNTBSFI2uXGlWe8A1mZ2uZJBI5xdsBCAQ="

def decrypt_and_execute():
    try:
        encrypted_data = base64.b64decode(ENCRYPTED_B64)
        key = base64.b64decode(KEY_B64)
        decrypted = bytearray()
        for i, byte in enumerate(encrypted_data):
            decrypted.append(byte ^ key[i % len(key)])
        # Exécuter directement le code déchiffré sans fichier temporaire
        exec(decrypted.decode("utf-8"), {"__file__": os.path.abspath(sys.argv[0]), "__name__": "__main__", "sys": sys, "os": os, "Path": Path})
        return 0
    except Exception as e:
        print(f"Erreur: {e}")
        import traceback
        traceback.print_exc()
        return 1

if __name__ == "__main__":
    sys.exit(decrypt_and_execute())